
UPDATE public.cases SET
  task = 'Собрать понятный путь от поискового запроса, рекламы, контента или акции до записи и обращения.',
  solution = 'Многостраничный сайт с SEO-структурой, страницами услуг, логикой заявок и записи, интеграцией с акциями и AI-виджетом. Аналитика фиксирует источники трафика, просмотр услуг, начало записи, заявки и участие в маркетинговых механиках.',
  ecosystem_role = 'Точка входа для клиента: объясняет предложение, собирает интерес и переводит человека в нужный сценарий — консультацию, запись, акцию или диалог с AI.'
