UPDATE public.cases SET
  task = 'Быстро и понятно отвечать клиентам, вести их к следующему действию и не терять обращения вне рабочего времени.',
  solution = 'AI-администратор с базой знаний, сценариями по услугам, Game Flow для игровых механик, Campaign Engine для акций и маркерной логикой. Система работает через VK, MAX и чат-виджет сайта, передаёт в CRM источник обращения, сценарий, тег услуги и задачу менеджеру. Рабочий контур размещён на российском сервере и использует YandexGPT. Персональные данные обрабатываются только в защищённом модуле записи.',
  ecosystem_role = 'Связывает маркетинговый интерес с записью: распознаёт сценарий, запускает нужную коммуникацию, передаёт сложные случаи человеку и ведёт клиента в модуль онлайн-записи.'
WHERE id = '6b34f859-8790-45d4-b82c-2b5fc51ddfa9';

UPDATE public.cases SET
  task = 'Дать владельцу прозрачный расчёт экономики услуг и основу для управленческих решений.',
  solution = 'Калькулятор рассчитывает стоимость услуги, расход материалов, оплату исполнителя, скидки, маржинальность и прибыль. На примере салона красоты он учитывает экономику процедур, но логика подходит разным сервисным бизнесам.',
