UPDATE public.cases SET
  task = 'Дать владельцу единый центр управления, который видит состояние цифровой системы, собирает данные, замечает отклонения и помогает бизнесу расти.',
  solution = 'OpenClaw работает через собственный пульт управления и внутренний мессенджер. Он объединяет задачи, календарь, почту, аналитику, статистику, маркетинговые гипотезы, мониторинг серверов и состояние интеграций. Перед любым критическим действием — изменением данных, внешней отправкой, перезапуском сервиса или вмешательством в процессы — OpenClaw запрашивает подтверждение владельца.',
  ecosystem_role = 'OpenClaw выступает как AI-директор над процессами: контролирует состояние серверов и сервисов, собирает сводки, замечает ошибки и точки внимания, помогает строить рекламные и маркетинговые стратегии, координирует задачи и поддерживает развитие бизнеса.'
WHERE id = '28cc71a6-16b7-4e3b-ad68-eb8ba19e2f80';
